#!/usr/bin/env python3

import argparse
import sys
from kafka.admin import KafkaAdminClient, NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import KafkaError, TopicAlreadyExistsError, UnknownTopicOrPartitionError


def create_admin_client(bootstrap_servers):
    try:
        admin_client = KafkaAdminClient(
            bootstrap_servers=bootstrap_servers,
            client_id='kafka-admin-script'
        )
        return admin_client
    except Exception as e:
        print(f"Error connecting to Kafka: {e}")
        sys.exit(1)


def create_topics(admin_client, topic_configs):
    topic_list = []
    for config in topic_configs:
        parts = config.split(':')
        topic_name = parts[0]
        num_partitions = int(parts[1]) if len(parts) > 1 else 1
        replication_factor = int(parts[2]) if len(parts) > 2 else 1
        
        topic_configs_dict = {}
        if len(parts) > 3:
            for cfg in parts[3].split(','):
                key, value = cfg.split('=')
                topic_configs_dict[key] = value
        
        new_topic = NewTopic(
            name=topic_name,
            num_partitions=num_partitions,
            replication_factor=replication_factor,
            topic_configs=topic_configs_dict if topic_configs_dict else None
        )
        topic_list.append(new_topic)
    
    try:
        result = admin_client.create_topics(new_topics=topic_list, validate_only=False)
        for topic, future in result.items():
            try:
                future.result()
                print(f"Topic '{topic}' created successfully")
            except TopicAlreadyExistsError:
                print(f"Topic '{topic}' already exists")
            except Exception as e:
                print(f"Failed to create topic '{topic}': {e}")
    except Exception as e:
        print(f"Error creating topics: {e}")


def delete_topics(admin_client, topic_names):
    try:
        result = admin_client.delete_topics(topics=topic_names)
        for topic, future in result.items():
            try:
                future.result()
                print(f"Topic '{topic}' deleted successfully")
            except UnknownTopicOrPartitionError:
                print(f"Topic '{topic}' does not exist")
            except Exception as e:
                print(f"Failed to delete topic '{topic}': {e}")
    except Exception as e:
        print(f"Error deleting topics: {e}")


def list_topics(admin_client):
    try:
        topics = admin_client.list_topics()
        print("Available topics:")
        for topic in sorted(topics):
            print(f"  - {topic}")
    except Exception as e:
        print(f"Error listing topics: {e}")


def describe_topics(admin_client, topic_names):
    try:
        metadata = admin_client._client.cluster
        metadata.request_update()
        admin_client._client.poll(future=None)
        
        for topic_name in topic_names:
            if topic_name in metadata.topics():
                topic_metadata = metadata.topics()[topic_name]
                print(f"\nTopic: {topic_name}")
                print(f"  Partitions: {len(topic_metadata)}")
                for partition_id, partition_metadata in topic_metadata.items():
                    print(f"    Partition {partition_id}:")
                    print(f"      Leader: {partition_metadata.leader}")
                    print(f"      Replicas: {partition_metadata.replicas}")
                    print(f"      ISR: {partition_metadata.isr}")
            else:
                print(f"Topic '{topic_name}' not found")
    except Exception as e:
        print(f"Error describing topics: {e}")


def alter_topic_configs(admin_client, topic_name, configs):
    config_dict = {}
    for config in configs:
        key, value = config.split('=')
        config_dict[key] = value
    
    try:
        config_resource = ConfigResource(ConfigResourceType.TOPIC, topic_name, configs=config_dict)
        result = admin_client.alter_configs([config_resource])
        
        for resource, future in result.items():
            try:
                future.result()
                print(f"Configuration for topic '{topic_name}' updated successfully")
            except Exception as e:
                print(f"Failed to update configuration for topic '{topic_name}': {e}")
    except Exception as e:
        print(f"Error altering topic configuration: {e}")


def describe_topic_configs(admin_client, topic_names):
    try:
        config_resources = [ConfigResource(ConfigResourceType.TOPIC, topic_name) for topic_name in topic_names]
        result = admin_client.describe_configs(config_resources)
        
        for resource, future in result.items():
            try:
                config = future.result()
                print(f"\nTopic: {resource.name}")
                print("  Configurations:")
                for config_name, config_value in config.resources[0][4].items():
                    print(f"    {config_name}: {config_value.value} (source: {config_value.source})")
            except Exception as e:
                print(f"Failed to describe configuration for topic '{resource.name}': {e}")
    except Exception as e:
        print(f"Error describing topic configurations: {e}")


def create_partitions(admin_client, topic_partition_map):
    from kafka.admin import NewPartitions
    
    partition_map = {}
    for item in topic_partition_map:
        topic, new_total = item.split(':')
        partition_map[topic] = NewPartitions(total_count=int(new_total))
    
    try:
        result = admin_client.create_partitions(partition_map)
        for topic, future in result.items():
            try:
                future.result()
                print(f"Partitions for topic '{topic}' created successfully")
            except Exception as e:
                print(f"Failed to create partitions for topic '{topic}': {e}")
    except Exception as e:
        print(f"Error creating partitions: {e}")


def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration Tool')
    parser.add_argument('--bootstrap-servers', required=True, help='Kafka bootstrap servers (comma-separated)')
    
    subparsers = parser.add_subparsers(dest='command', help='Command to execute')
    
    create_parser = subparsers.add_parser('create', help='Create topics')
    create_parser.add_argument('topics', nargs='+', 
                              help='Topic configurations in format: name:partitions:replication:config1=value1,config2=value2')
    
    delete_parser = subparsers.add_parser('delete', help='Delete topics')
    delete_parser.add_argument('topics', nargs='+', help='Topic names to delete')
    
    list_parser = subparsers.add_parser('list', help='List all topics')
    
    describe_parser = subparsers.add_parser('describe', help='Describe topics')
    describe_parser.add_argument('topics', nargs='+', help='Topic names to describe')
    
    alter_parser = subparsers.add_parser('alter-config', help='Alter topic configuration')
    alter_parser.add_argument('topic', help='Topic name')
    alter_parser.add_argument('configs', nargs='+', help='Configurations in format: key=value')
    
    describe_config_parser = subparsers.add_parser('describe-config', help='Describe topic configuration')
    describe_config_parser.add_argument('topics', nargs='+', help='Topic names')
    
    add_partitions_parser = subparsers.add_parser('add-partitions', help='Add partitions to topics')
    add_partitions_parser.add_argument('partitions', nargs='+', 
                                       help='Topic and partition count in format: topic:new_total_count')
    
    args = parser.parse_args()
    
    if not args.command:
        parser.print_help()
        sys.exit(1)
    
    bootstrap_servers = args.bootstrap_servers.split(',')
    admin_client = create_admin_client(bootstrap_servers)
    
    try:
        if args.command == 'create':
            create_topics(admin_client, args.topics)
        elif args.command == 'delete':
            delete_topics(admin_client, args.topics)
        elif args.command == 'list':
            list_topics(admin_client)
        elif args.command == 'describe':
            describe_topics(admin_client, args.topics)
        elif args.command == 'alter-config':
            alter_topic_configs(admin_client, args.topic, args.configs)
        elif args.command == 'describe-config':
            describe_topic_configs(admin_client, args.topics)
        elif args.command == 'add-partitions':
            create_partitions(admin_client, args.partitions)
    finally:
        admin_client.close()


if __name__ == '__main__':
    main()